        User newUser = User.builder()
                .id((long) (userStore.size() + 1)).username(username)
                .password(passwordEncoder.encode(body.get("password")))
                .role(UserRole.CLIENTE)
                .fullName(body.getOrDefault("fullName", username)).active(true).build();
        userStore.put(username, newUser);
        return Map.of("message", "Conta criada com sucesso!", "username", username);
